var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치 이야기는 평소에도 다른 직원들에게 많이 들었어요.","JPN":"コーチについてのお話は日頃社員の方からたくさん聞いてます。","ENG":"I've heard a lot about you from your other employees.","TWN":"我平時也常聽到其他員工談論教練的事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"물론 저는 어른들의 칭찬에 속지 않아요.","JPN":"もちろん、私は大人の賞賛には騙されませんが。","ENG":"Of course, I don't fall for adults' fake compliments.","TWN":"不過，我是不會被大人稱讚的話給欺騙的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"다들 자기가 했던 말을 손바닥처럼 뒤집으니까요.","JPN":"大人はみんな、自分が言ったことを手の平をかえすように変えますから。","ENG":"They always go back on their word like it's nothing.","TWN":"因為大家總是會輕易推翻自己說過的話。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래서 저는 제가 본 코치만 믿을 거예요.","JPN":"私は私が知るコーチだけを信じます。","ENG":"So I'm only going to believe in you that I witnessed with my own two eyes.","TWN":"所以我只相信眼見為憑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제가 봤던 코치는 괴짜에, 무슨 생각을 하고 사는지 모를 사람이지만….","JPN":"私が知るコーチは変人で、何を考えて生きているのか全くわからない人ですが……","ENG":"From what I've observed, you're a freak and someone who is very mysterious...","TWN":"我所看到的教練是個怪人，不知道你每天都在想些什麼……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제 꿈을 듣고 비웃을 사람은 아니라고 생각해요.","JPN":"私の夢を聞いて笑うような人ではないと思います。","ENG":"But I don't think you're someone who'd laugh at my dreams.","TWN":"但我覺得你不是那種聽到我的夢想後會嘲笑我的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저는 혼자 방패도 들고 다닐 수 있고, 턱걸이도 많이 하고.","JPN":"私はひとりで盾を持ち歩くこともできるし、けんすいもたくさんしているし。","ENG":"I have no problem carrying around my shield and I do a lot of pull-ups.","TWN":"我可以一個人扛著盾牌跑，也可以做很多個引體向上。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"덩치가 작으니까 난전이나 야전에도 유리하고, 시가전은 어른들보다 훨씬 잘해요.","JPN":"身体が小さいので乱戦や野戦でも有利ですし、市街戦も大人よりずっと上手いです。","ENG":"I'm petite, so I have the advantage in dogfights and field operations, and I'm much better at street battles than adults.","TWN":"因為個子不高，所以在混戰和野戰中都很有利，巷戰也比大人強。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치의 지시대로 움직일 때는, 꼭 다른 사람이 된 것 같은 기분이었어요.","JPN":"コーチの指示どおりに動く時は他の人になったような気分になったんです。","ENG":"It felt like I was a different person when I was following your instructions.","TWN":"按照教練的指示行動時，我有種變成別人的感覺。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저는 코치를 따르는 다른 직원들처럼 강하진 않아요.","JPN":"私はコーチと一緒にいる他の社員のように強くありません。","ENG":"I'm not as strong as the other employees who follow you.","TWN":"我不像其他跟隨教練的員工厲害。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만 코치의 지시라면, 불평 불만 없이 꾹 믿고 따를게요.","JPN":"でも、コーチの指示なら文句を言わずに絶対信じて従います。","ENG":"But if it's your instruction, I'm going to follow it no questions asked.","TWN":"但只要是教練的指令，我一定二話不說立刻執行。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 가르쳐 주세요, 코치. 제가 이길 수 있는 길을요.","JPN":"だから、教えてください、コーチ。勝てる道を。","ENG":"So teach me, Coach. How I can win.","TWN":"所以請繼續教導我吧，教練。引導我通往勝利的道路。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};